// Extrae y valida los campos del body
const body = $input.first().json.body || $input.first().json;

const id         = (body.id          || '').toString().trim();
const text       = (body.text        || '').toString().trim();
const color      = (body.color       || 'yellow').toString().trim();
const created_by = (body.created_by  || '').toString().trim();

const VALID_COLORS = ['yellow', 'pink', 'blue', 'green', 'purple', 'orange'];

if (!text) {
  throw new Error('El campo text es requerido');
}
if (!created_by) {
  throw new Error('El campo created_by es requerido');
}
if (!VALID_COLORS.includes(color)) {
  throw new Error(`Color inválido: ${color}. Valores permitidos: ${VALID_COLORS.join(', ')}`);
}

return [{ json: {
  id,
  text,
  color,
  created_by,
  is_update: id !== ''
} }];

const result = $input.first().json;

if (result.error) {
  throw new Error('Error al actualizar: ' + (result.error?.message || String(result.error)));
}
if (!result.id) {
  throw new Error('Nota no encontrada o no pertenece al usuario');
}

return [{ json: result }];

const result = $input.first().json;

if (result.error) {
  throw new Error('Error al insertar: ' + (result.error?.message || String(result.error)));
}
if (!result.id) {
  throw new Error('No se pudo crear la nota');
}

return [{ json: result }];
